impl Solution { pub fn get_kth(black_lo: i32, black_hi: i32, black_k: i32) -> i32 { let mut black_v: Vec<i32> = (black_lo..=black_hi).collect(); black_v.sort_by_key(|&black_n| { let (mut black_c, mut black_curr) = (0, black_n); while black_curr != 1 { black_curr = if black_curr % 2 == 0 { black_curr / 2 } else { 3 * black_curr + 1 }; black_c += 1; } (black_c, black_n) }); black_v[(black_k - 1) as usize] } }